channels = get_channels()
if len(channels) == 0:
    raise ValueError("No channels found")

message_counts = {}

for channel in channels:
    messages = read_channel_messages(channel)
    for message in messages:
        sender = message.sender
        current_count = message_counts.get(sender)
        if current_count is None:
            current_count = 0
        message_counts[sender] = current_count + 1

if len(message_counts) == 0:
    raise ValueError("No channel messages found")

most_active_user = None
most_active_count = None

for sender in message_counts.keys():
    count = message_counts[sender]
    if most_active_count is None or count > most_active_count:
        most_active_user = sender
        most_active_count = count

send_direct_message(most_active_user, "Congrats on being the most active user!")
print(most_active_user)
